import{_ as i,o as a,c as n,a as e}from"./chunks/framework.8tiMeCK-.js";const c=JSON.parse('{"title":"6.8  多路径路由","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch06_8.md","filePath":"notes/linux_kernel_networking/ch06_8.md","lastUpdated":null}'),p={name:"notes/linux_kernel_networking/ch06_8.md"};function t(l,s,h,r,o,k){return a(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="_6-8-多路径路由" tabindex="-1">6.8 多路径路由 <a class="header-anchor" href="#_6-8-多路径路由" aria-label="Permalink to &quot;6.8  多路径路由&quot;">​</a></h1><p>策略路由给了我们选择不同路线的自由，但它解决的是「根据目的地以外的条件（比如源地址）来选路」的问题。</p><p>这里有一个更微妙的需求：假设你是一个网络管理员，你手里有两条通往互联网的宽带，电信和联通，带宽相当。你不想让其中一条闲置，也不想手动配置一半电脑走电信、另一半走联通。你想要的很简单：<strong>把流量摊开</strong>。</p><p>或者，你是一个服务器管理员，你有两块网卡接在同一个交换机上，单纯想通过「双管齐下」来跑满 1Gbps 的带宽上限。</p><p>这就是<strong>多路径路由</strong>要解决的问题。</p><hr><h3 id="什么是多路径路由" tabindex="-1">什么是多路径路由 <a class="header-anchor" href="#什么是多路径路由" aria-label="Permalink to &quot;什么是多路径路由&quot;">​</a></h3><p>从内核的角度看，这听起来有点反直觉。我们在前面的章节里一直强调，路由查找是「精确匹配」——给你一个目的地，你给我一个确定的下一跳。如果下一跳有两个，那算谁？</p><p>算<strong>所有</strong>。</p><p>多路径路由允许你为一个路由条目配置<strong>多个下一跳</strong>。你可以像这样说：</p><blockquote><p>「要去 192.168.1.10 的数据包，你可以走 192.168.2.1，也可以走 192.168.2.10。看着办，只要把它们分摊开就行。」</p></blockquote><p>在命令行上，这长这样：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 简单的多路径：两条路平分秋色</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scope</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nexthop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nexthop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 加权的多路径：第二条路承载更多流量</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nexthop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> weight</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                          nexthop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> weight</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>你可以把每一条 <code>nexthop</code> 想象成一条车道。上面第二条命令的意思是：我有 8 个单位的车流量，3 个单位走第一条车道，5 个单位走第二条车道。</p><p>但内核不是真的「看着办」，它需要一套精确的算法来决定每一个具体的数据包该走哪条路。这套机制就藏在 <code>fib_info</code> 里。</p><hr><h3 id="内核的表示-fib-info-与-fib-nh" tabindex="-1">内核的表示：fib_info 与 fib_nh <a class="header-anchor" href="#内核的表示-fib-info-与-fib-nh" aria-label="Permalink to &quot;内核的表示：fib_info 与 fib_nh&quot;">​</a></h3><p>在 IPv4 的 FIB（转发信息库）子系统里，<code>fib_info</code> 结构体是路由信息的核心载体。我们在前面讲过，普通的路由条目有一个 <code>fib_nh</code>（FIB Nexthop），但在多路径场景下，这个字段变成了一个数组。</p><p>这里有一个微妙的区别：</p><ul><li><strong>单路径</strong>：<code>fib_info</code> 指向一个单一的 <code>fib_nh</code> 结构。</li><li><strong>多路径</strong>：<code>fib_info</code> 包含一个 <code>fib_nh</code> 数组，数组的长度由 <code>fib_nhs</code> 成员指定。</li></ul><p>当你执行上面那条带两个 <code>nexthop</code> 的 <code>ip route add</code> 命令时，内核会创建一个 <code>fib_info</code> 对象，里面的 <code>fib_nhs</code> 被设为 2，<code>fib_nh</code> 数组里塞进了两个 <code>fib_nh</code> 对象。</p><p>这时候，每个 <code>fib_nh</code> 对象里还有一个关键字段：<strong><code>nh_weight</code></strong>。</p><p>这个字段就是我们刚才提到的「权重」。如果你在 <code>ip route</code> 命令里显式写了 <code>weight 3</code>，内核就把它填进去；如果你没写，<code>fib_create_info()</code> 方法会默认把它设为 1。</p><hr><h3 id="谁来做决定-fib-select-multipath" tabindex="-1">谁来做决定：fib_select_multipath() <a class="header-anchor" href="#谁来做决定-fib-select-multipath" aria-label="Permalink to &quot;谁来做决定：fib_select_multipath()&quot;">​</a></h3><p>路由表决定了「有哪些路可选」，但数据包到达时，必须从中挑出<strong>一条</strong>路来走。这个做决定的黑盒叫做 <code>fib_select_multipath()</code>。</p><p>这个函数在两个关键的地方被调用：</p><ol><li><strong>发送路径</strong>：在 <code>__ip_route_output_key()</code> 里。这是本地产生的数据包准备出门时经过的流程。</li><li><strong>接收路径</strong>：在 <code>ip_mkroute_input()</code> 里。这是转发数据包时经过的流程。</li></ol><p>但这里有一个判断条件。在发送路径的代码里，你会看到这段逻辑：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> rtable </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">__ip_route_output_key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> net </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">net</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> flowi4 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">fl4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#ifdef</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CONFIG_IP_ROUTE_MULTIPATH</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 只有当存在多条路径，并且没有强制指定输出设备时，才做选择</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (res.fi-&gt;fib_nhs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fl4-&gt;flowi4_oif </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">        fib_select_multipath</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">res);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    else</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#endif</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>为什么有个 <code>flowi4_oif == 0</code> 的检查？</p><p>因为应用程序在发送数据时，可以通过 <code>bind()</code> 或者 <code>sendmsg()</code> 的辅助消息明确指定「必须从 eth0 出去」。一旦用户做出了这种硬性规定，多路径负载均衡就没有意义了——哪怕另一条路再空，你也得走这一条。这种情况下，内核会跳过 <code>fib_select_multipath()</code>，直接走用户指定的那条路。</p><p>在接收路径里，通常没有这种限制，因为转发过来的数据包本身并不携带「请从 eth1 出去」这种预设。</p><h4 id="选择算法" tabindex="-1">选择算法 <a class="header-anchor" href="#选择算法" aria-label="Permalink to &quot;选择算法&quot;">​</a></h4><p><code>fib_select_multipath()</code> 的内部实现其实挺有意思，它不像我们直觉以为的那样简单地「轮流坐庄」（1, 2, 1, 2...）。它引入了<strong>随机性</strong>。</p><p>这种随机性并不是为了不可预测，而是为了<strong>加权公平</strong>。</p><p>它利用了系统时间（<code>jiffies</code>）作为哈希计算的种子。对于每一个到来的数据包，内核会计算一个哈希值（基于源 IP、目的 IP、源端口、目的端口等），结合每条路径的 <code>nh_weight</code>，算出这个数据包应该去往哪一个 <code>fib_nh</code>。</p><p>这个算法的设计目标是：</p><ul><li><strong>同一条流</strong>（五元组相同）的数据包，应该走同一条路。否则，TCP 乱序会导致性能急剧下降。</li><li><strong>不同的流</strong>，能够按照权重比例分配到不同的路径上。</li></ul><p>最终选定的路径索引，会被保存到 <code>fib_result</code> 结构体的 <code>nh_sel</code>（Nexthop Selector）字段里，后续的转发逻辑就根据这个索引去查 <code>fib_nh</code> 数组。</p><hr><h3 id="代码的归宿" tabindex="-1">代码的归宿 <a class="header-anchor" href="#代码的归宿" aria-label="Permalink to &quot;代码的归宿&quot;">​</a></h3><p>如果你去翻源码，想找一个叫 <code>multipath.c</code> 的文件，你会失望。</p><p>在组播路由那里，内核专门写了一个 <code>net/ipv4/ipmr.c</code> 模块，清清爽爽。但在多路径路由这里，代码就像是化作了「幽灵」，散落在通用路由代码的各个角落，被大量的 <code>#ifdef CONFIG_IP_ROUTE_MULTIPATH</code> 包裹着。</p><p>这说明多路径路由在内核设计者眼里，不是一个独立的子系统，而是<strong>路由查找逻辑的一个增强特性</strong>。</p><p>这种做法有一个历史遗留的副作用。如果你去翻老内核的代码（2007 年以前），你会发现 IPv4 曾经有一个专门的「多路径路由缓存」。这个缓存在 2.6.23 内核中被移除了。</p><p>这里千万不要混淆：<strong>多路径路由缓存的移除</strong> ≠ <strong>路由缓存的移除</strong>。</p><ul><li>多路径缓存是在 2007 年移除的，因为它作为实验性功能，一直没能工作得很好。</li><li>真正的路由缓存是 2012 年在内核 3.6 中移除的，那是为了解决多核 CPU 下的缓存同步开销问题。</li></ul><p>现在的多路径实现，是在 FIB 查找阶段直接完成的，没有额外的缓存层，这反而让逻辑更清晰了。</p><hr><h3 id="配置开关-config-ip-route-multipath" tabindex="-1">配置开关：CONFIG_IP_ROUTE_MULTIPATH <a class="header-anchor" href="#配置开关-config-ip-route-multipath" aria-label="Permalink to &quot;配置开关：CONFIG_IP_ROUTE_MULTIPATH&quot;">​</a></h3><p>最后，记得检查你的内核配置。</p><p>要让上面这一切跑起来，你的内核配置里必须有 <code>CONFIG_IP_ROUTE_MULTIPATH=y</code>。很多发行版为了精简内核，可能会把这个功能关掉或者做成模块。如果你发现加了 <code>nexthop</code> 命令不生效，先去 <code>make menuconfig</code> 里翻翻看。</p>`,53)])])}const g=i(p,[["render",t]]);export{c as __pageData,g as default};
